  subscription?: Prisma.SubscriptionOmit
  creditLedger?: Prisma.CreditLedgerOmit
  usageEvent?: Prisma.UsageEventOmit
  chatSession?: Prisma.ChatSessionOmit
  chatMessage?: Prisma.ChatMessageOmit
  toolCallLog?: Prisma.ToolCallLogOmit
  featureSession?: Prisma.FeatureSessionOmit
  requirement?: Prisma.RequirementOmit
  designDecision?: Prisma.DesignDecisionOmit
  classificationDecision?: Prisma.ClassificationDecisionOmit
  analysisFinding?: Prisma.AnalysisFindingOmit
  integrationPoint?: Prisma.IntegrationPointOmit
  testCase?: Prisma.TestCaseOmit
  implementationTask?: Prisma.ImplementationTaskOmit
  taskDependency?: Prisma.TaskDependencyOmit
  testSpecification?: Prisma.TestSpecificationOmit
  implementationRun?: Prisma.ImplementationRunOmit
  taskExecution?: Prisma.TaskExecutionOmit
  componentDefinition?: Prisma.ComponentDefinitionOmit
  registry?: Prisma.RegistryOmit
